import{_ as n,c as t,o as e,a1 as s}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"計畫審查: 視覺化審查 AI 計畫 | Plannotator","description":"學習 Plannotator 計畫審查功能。使用視覺化介面審查 AI 產生的計畫，新增註解批准或拒絕，掌握 Approve 和 Request Changes 的區別。","frontmatter":{"title":"計畫審查: 視覺化審查 AI 計畫 | Plannotator","subtitle":"計畫審查基礎：視覺化審查 AI 計畫","description":"學習 Plannotator 計畫審查功能。使用視覺化介面審查 AI 產生的計畫，新增註解批准或拒絕，掌握 Approve 和 Request Changes 的區別。","sidebarTitle":"5 分鐘學會審查計畫","tags":["計畫審查","視覺化審查","註解","批准","拒絕","Claude Code","OpenCode"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"zh-tw/backnotprop/plannotator/platforms/plan-review-basics/index.md","filePath":"zh-tw/backnotprop/plannotator/platforms/plan-review-basics/index.md"}'),o={name:"zh-tw/backnotprop/plannotator/platforms/plan-review-basics/index.md"};function l(p,a,i,r,d,c){return e(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="計畫審查基礎-視覺化審查-ai-計畫" tabindex="-1">計畫審查基礎：視覺化審查 AI 計畫 <a class="header-anchor" href="#計畫審查基礎-視覺化審查-ai-計畫" aria-label="Permalink to &quot;計畫審查基礎：視覺化審查 AI 計畫&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>✅ 使用 Plannotator 視覺化介面審查 AI 產生的計畫</li><li>✅ 選取計畫文字，新增不同類型的註解（刪除、取代、評論）</li><li>✅ 批准計畫，讓 AI 繼續實施</li><li>✅ 拒絕計畫，將註解作為回饋傳送給 AI</li><li>✅ 理解註解類型的使用情境和區別</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p><strong>問題 1</strong>：AI 產生的實施計畫在終端機裡閱讀，文字量大、結構不清晰，審查起來很累。</p><p><strong>問題 2</strong>：想給 AI 回饋時，只能用文字描述「刪除第 3 段」、「修改這個函式」，溝通成本高，AI 也可能理解錯誤。</p><p><strong>問題 3</strong>：計畫中有些地方不需要修改，有些地方需要取代，有些地方需要評論，但沒有工具幫你結構化這些回饋。</p><p><strong>問題 4</strong>：不知道如何讓 AI 知道你批准了計畫，還是需要修改。</p><p><strong>Plannotator 能幫你</strong>：</p><ul><li>視覺化 UI 取代終端機閱讀，結構清晰</li><li>選取文字即可新增註解（刪除、取代、評論），精確回饋</li><li>註解自動轉換為結構化資料，AI 準確理解你的意圖</li><li>一鍵批准或拒絕，AI 立即回應</li></ul><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><p><strong>使用情境</strong>：</p><ul><li>AI Agent 完成計畫並呼叫 <code>ExitPlanMode</code>（Claude Code）</li><li>AI Agent 呼叫 <code>submit_plan</code> 工具（OpenCode）</li><li>需要審查 AI 產生的實施計畫</li><li>需要精確回饋計畫的修改意見</li></ul><p><strong>不適用情境</strong>：</p><ul><li>直接讓 AI 實施程式碼（跳過計畫審查）</li><li>已經批准計畫，需要審查實際程式碼變更（使用程式碼審查功能）</li></ul><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><p><strong>前置條件</strong>：</p><ul><li>✅ 已安裝 Plannotator CLI（詳見 <a href="./../start/getting-started/">快速開始</a>）</li><li>✅ 已設定 Claude Code 或 OpenCode 外掛（詳見對應安裝指南）</li><li>✅ AI Agent 支援計畫審查（Claude Code 2.1.7+，或 OpenCode）</li></ul><p><strong>觸發方式</strong>：</p><ul><li><strong>Claude Code</strong>：AI 完成 plan 後自動呼叫 <code>ExitPlanMode</code>，Plannotator 自動啟動</li><li><strong>OpenCode</strong>：AI 呼叫 <code>submit_plan</code> 工具，Plannotator 自動啟動</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="計畫審查是什麼" tabindex="-1">計畫審查是什麼 <a class="header-anchor" href="#計畫審查是什麼" aria-label="Permalink to &quot;計畫審查是什麼&quot;">​</a></h3><p><strong>計畫審查</strong>是 Plannotator 的核心功能，用於視覺化審查 AI 產生的實施計畫。</p><div class="info custom-block"><p class="custom-block-title">為什麼需要計畫審查？</p><p>AI 產生計畫後，通常會問「這個計畫可以嗎？」或「是否開始實施？」。如果沒有視覺化工具，你只能在終端機裡閱讀純文字計畫，然後回覆「可以」、「不行，修改 XX」等模糊回饋。Plannotator 讓你用視覺化介面檢視計畫，精確選取需要修改的部分，新增結構化註解，AI 更容易理解你的意圖。</p></div><h3 id="運作流程" tabindex="-1">運作流程 <a class="header-anchor" href="#運作流程" aria-label="Permalink to &quot;運作流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (產生計畫)    │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ ExitPlanMode / submit_plan</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│ Plannotator UI  │  ← 瀏覽器自動開啟</span></span>
<span class="line"><span>│                 │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ 計畫內容   │  │</span></span>
<span class="line"><span>│ │ (Markdown) │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       │ 選取文字</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ 新增註解   │  │</span></span>
<span class="line"><span>│ │ Delete/    │  │</span></span>
<span class="line"><span>│ │ Replace/   │  │</span></span>
<span class="line"><span>│ │ Comment    │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ 決策      │  │</span></span>
<span class="line"><span>│ │ Approve/  │  │</span></span>
<span class="line"><span>│ │ Request   │  │</span></span>
<span class="line"><span>│ │ Changes   │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;allow&quot;} 或</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (繼續實施)    │</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><h3 id="註解類型" tabindex="-1">註解類型 <a class="header-anchor" href="#註解類型" aria-label="Permalink to &quot;註解類型&quot;">​</a></h3><p>Plannotator 支援四種註解類型，每種都有不同的用途：</p><table tabindex="0"><thead><tr><th>註解類型</th><th>用途</th><th>AI 收到的回饋</th></tr></thead><tbody><tr><td><strong>Delete</strong></td><td>刪除不需要的內容</td><td>「刪除：[選取的文字]」</td></tr><tr><td><strong>Replace</strong></td><td>取代為更好的內容</td><td>「取代：[選取的文字] 為 [你輸入的文字]」</td></tr><tr><td><strong>Comment</strong></td><td>評論某段內容，不要求修改</td><td>「評論：[選取的文字]。說明：[你輸入的評論]」</td></tr><tr><td><strong>Global Comment</strong></td><td>全域評論，不關聯具體文字</td><td>「全域評論：[你輸入的評論]」</td></tr></tbody></table><h3 id="approve-vs-request-changes" tabindex="-1">Approve vs Request Changes <a class="header-anchor" href="#approve-vs-request-changes" aria-label="Permalink to &quot;Approve vs Request Changes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>決策類型</th><th>操作</th><th>AI 收到的回饋</th><th>適用情境</th></tr></thead><tbody><tr><td><strong>Approve</strong></td><td>點擊 Approve 按鈕</td><td><code>{&quot;behavior&quot;: &quot;allow&quot;}</code></td><td>計畫沒問題，直接批准</td></tr><tr><td><strong>Request Changes</strong></td><td>點擊 Request Changes 按鈕</td><td><code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></td><td>有需要修改的地方</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Claude Code 和 OpenCode 的差異</p><ul><li><strong>Claude Code</strong>：Approve 時不會傳送註解（註解會被忽略）</li><li><strong>OpenCode</strong>：Approve 時可以傳送註解作為備註（可選）</li></ul><p><strong>拒絕計畫時</strong>：無論哪個平台，註解都會傳送給 AI</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-觸發計畫審查" tabindex="-1">第 1 步：觸發計畫審查 <a class="header-anchor" href="#第-1-步-觸發計畫審查" aria-label="Permalink to &quot;第 1 步：觸發計畫審查&quot;">​</a></h3><p><strong>Claude Code 範例</strong>：</p><p>在 Claude Code 中與 AI 對話，讓 AI 產生一個實施計畫：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者：幫我寫一個使用者認證模組的實施計畫</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude：好的，這是實施計畫：</span></span>
<span class="line"><span>1. 建立使用者模型</span></span>
<span class="line"><span>2. 實作註冊 API</span></span>
<span class="line"><span>3. 實作登入 API</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>（AI 呼叫 ExitPlanMode）</span></span></code></pre></div><p><strong>OpenCode 範例</strong>：</p><p>在 OpenCode 中，AI 會自動呼叫 <code>submit_plan</code> 工具。</p><p><strong>你應該看到</strong>：</p><ol><li>瀏覽器自動開啟 Plannotator UI</li><li>顯示 AI 產生的計畫內容（Markdown 格式）</li><li>頁面底部有「Approve」和「Request Changes」按鈕</li></ol><h3 id="第-2-步-瀏覽計畫內容" tabindex="-1">第 2 步：瀏覽計畫內容 <a class="header-anchor" href="#第-2-步-瀏覽計畫內容" aria-label="Permalink to &quot;第 2 步：瀏覽計畫內容&quot;">​</a></h3><p>在瀏覽器中檢視計畫：</p><ul><li>計畫以 Markdown 格式渲染，包括標題、段落、清單、程式碼區塊</li><li>可以捲動檢視整個計畫</li><li>支援亮/暗模式切換（點擊右上角的主題切換按鈕）</li></ul><h3 id="第-3-步-選取計畫文字-新增註解" tabindex="-1">第 3 步：選取計畫文字，新增註解 <a class="header-anchor" href="#第-3-步-選取計畫文字-新增註解" aria-label="Permalink to &quot;第 3 步：選取計畫文字，新增註解&quot;">​</a></h3><p><strong>新增 Delete 註解</strong>：</p><ol><li>用滑鼠選取計畫中需要刪除的文字</li><li>在彈出的工具列中點擊 <strong>Delete</strong> 按鈕</li><li>文字會被標記為刪除樣式（紅色刪除線）</li></ol><p><strong>新增 Replace 註解</strong>：</p><ol><li>用滑鼠選取計畫中需要取代的文字</li><li>在彈出的工具列中點擊 <strong>Replace</strong> 按鈕</li><li>在彈出的輸入框中輸入取代後的內容</li><li>按 Enter 或點擊確認</li><li>原文字會被標記為取代樣式（黃色背景），並在下方顯示取代內容</li></ol><p><strong>新增 Comment 註解</strong>：</p><ol><li>用滑鼠選取計畫中需要評論的文字</li><li>在彈出的工具列中點擊 <strong>Comment</strong> 按鈕</li><li>在彈出的輸入框中輸入評論內容</li><li>按 Enter 或點擊確認</li><li>文字會被標記為評論樣式（藍色醒目提示），並在側邊欄顯示評論</li></ol><p><strong>新增 Global Comment</strong>：</p><ol><li>點擊頁面右上角的 <strong>Add Global Comment</strong> 按鈕</li><li>在彈出的輸入框中輸入全域評論內容</li><li>按 Enter 或點擊確認</li><li>評論會顯示在側邊欄的「Global Comments」部分</li></ol><p><strong>你應該看到</strong>：</p><ul><li>選取文字後，會立即彈出工具列（Delete、Replace、Comment）</li><li>新增註解後，文字會顯示相應的樣式（刪除線、背景色、醒目提示）</li><li>側邊欄會顯示所有註解清單，可以點擊跳轉到對應位置</li><li>可以點擊註解旁的 <strong>刪除</strong> 按鈕移除註解</li></ul><h3 id="第-4-步-批准計畫" tabindex="-1">第 4 步：批准計畫 <a class="header-anchor" href="#第-4-步-批准計畫" aria-label="Permalink to &quot;第 4 步：批准計畫&quot;">​</a></h3><p><strong>如果計畫沒有問題</strong>：</p><p>點擊頁面底部的 <strong>Approve</strong> 按鈕。</p><p><strong>你應該看到</strong>：</p><ul><li>瀏覽器自動關閉（1.5 秒延遲）</li><li>Claude Code/OpenCode 終端機中顯示計畫已批准</li><li>AI 繼續實施計畫</li></ul><div class="info custom-block"><p class="custom-block-title">Approve 的行為</p><ul><li><strong>Claude Code</strong>：只傳送 <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>，註解被忽略</li><li><strong>OpenCode</strong>：傳送 <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>，註解可以作為備註傳送（可選）</li></ul></div><h3 id="第-5-步-拒絕計畫-request-changes" tabindex="-1">第 5 步：拒絕計畫（Request Changes） <a class="header-anchor" href="#第-5-步-拒絕計畫-request-changes" aria-label="Permalink to &quot;第 5 步：拒絕計畫（Request Changes）&quot;">​</a></h3><p><strong>如果計畫需要修改</strong>：</p><ol><li>新增必要的註解（Delete、Replace、Comment）</li><li>點擊頁面底部的 <strong>Request Changes</strong> 按鈕</li><li>瀏覽器會顯示確認對話框</li></ol><p><strong>你應該看到</strong>：</p><ul><li>確認對話框顯示「Send X annotations to AI?」</li><li>點擊確認後，瀏覽器自動關閉</li><li>Claude Code/OpenCode 終端機中顯示回饋內容</li><li>AI 會根據回饋修改計畫</li></ul><div class="tip custom-block"><p class="custom-block-title">Request Changes 的行為</p><ul><li><strong>Claude Code</strong> 和 <strong>OpenCode</strong>：都會傳送 <code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></li><li>註解會被轉換為結構化的 Markdown 文字</li><li>AI 會根據註解修改計畫並再次呼叫 ExitPlanMode/submit_plan</li></ul></div><h3 id="第-6-步-檢視回饋內容-可選" tabindex="-1">第 6 步：檢視回饋內容（可選） <a class="header-anchor" href="#第-6-步-檢視回饋內容-可選" aria-label="Permalink to &quot;第 6 步：檢視回饋內容（可選）&quot;">​</a></h3><p>如果你想檢視 Plannotator 傳送給 AI 的回饋內容，可以在終端機中檢視：</p><p><strong>Claude Code</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan rejected by user</span></span>
<span class="line"><span>Please modify the plan based on the following feedback:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[結構化的註解內容]</span></span></code></pre></div><p><strong>OpenCode</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;feedback&gt;</span></span>
<span class="line"><span>[結構化的註解內容]</span></span>
<span class="line"><span>&lt;/feedback&gt;</span></span></code></pre></div><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><p>完成以上步驟後，你應該能夠：</p><ul><li>[ ] 在 AI 觸發計畫審查後，瀏覽器自動開啟 Plannotator UI</li><li>[ ] 選取計畫文字，新增 Delete、Replace、Comment 註解</li><li>[ ] 新增 Global Comment</li><li>[ ] 在側邊欄檢視所有註解，並跳轉到對應位置</li><li>[ ] 點擊 Approve，瀏覽器關閉，AI 繼續實施</li><li>[ ] 點擊 Request Changes，瀏覽器關閉，AI 修改計畫</li></ul><p><strong>如果某一步失敗</strong>，詳見：</p><ul><li><a href="./../../faq/common-problems/">常見問題</a></li><li><a href="./../../start/installation-claude-code/">Claude Code 安裝指南</a></li><li><a href="./../../start/installation-opencode/">OpenCode 安裝指南</a></li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><p><strong>常見錯誤 1</strong>：選取文字後，工具列沒有彈出</p><p><strong>原因</strong>：可能是因為選取的是程式碼區塊中的文字，或者選取的文字跨多個元素。</p><p><strong>解決</strong>：</p><ul><li>儘量選取單個段落或清單項目中的文字</li><li>對於���式碼區塊，可以使用 Comment 註解，不要跨多行選取</li></ul><p><strong>常見錯誤 2</strong>：新增 Replace 註解後，取代內容沒有顯示</p><p><strong>原因</strong>：取代內容輸入框可能沒有正確提交。</p><p><strong>解決</strong>：</p><ul><li>輸入取代內容後，按 Enter 鍵或點擊確認按鈕</li><li>檢查側邊欄中是否顯示了取代內容</li></ul><p><strong>常見錯誤 3</strong>：點擊 Approve 或 Request Changes 後，瀏覽器沒有關閉</p><p><strong>原因</strong>：可能是伺服器錯誤或網路問題。</p><p><strong>解決</strong>：</p><ul><li>檢查終端機中是否有錯誤訊息</li><li>手動關閉瀏覽器</li><li>如果問題持續，詳見 <a href="./../../faq/troubleshooting/">故障排除</a></li></ul><p><strong>常見錯誤 4</strong>：AI 收到回饋後，沒有按照註解修改</p><p><strong>原因</strong>：AI 可能沒有正確理解註解的意圖。</p><p><strong>解決</strong>：</p><ul><li>嘗試使用更明確的註解（Replace 比 Comment 更明確）</li><li>使用 Comment 新增詳細說明</li><li>如果問題持續，可以再次拒絕計畫，並調整註解內容</li></ul><p><strong>常見錯誤 5</strong>：新增多個 Delete 註解後，AI 只刪除了部分內容</p><p><strong>原因</strong>：多個 Delete 註解之間可能有重疊或衝突。</p><p><strong>解決</strong>：</p><ul><li>確保每個 Delete 註解的文字範圍不重疊</li><li>如果需要刪除大段內容，可以選取整個段落一次性刪除</li></ul><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>計畫審查是 Plannotator 的核心功能，讓你可以視覺化審查 AI 產生的計畫：</p><p><strong>核心操作</strong>：</p><ol><li><strong>觸發</strong>：AI 呼叫 <code>ExitPlanMode</code> 或 <code>submit_plan</code>，瀏覽器自動開啟 UI</li><li><strong>瀏覽</strong>：在視覺化介面中檢視計畫內容（Markdown 格式）</li><li><strong>註解</strong>：選取文字，新增 Delete、Replace、Comment 或 Global Comment</li><li><strong>決策</strong>：點擊 Approve（批准）或 Request Changes（拒絕）</li><li><strong>回饋</strong>：註解被轉換為結構化資料，AI 根據回饋繼續或修改計畫</li></ol><p><strong>註解類型</strong>：</p><ul><li><strong>Delete</strong>：刪除不需要的內容</li><li><strong>Replace</strong>：取代為更好的內容</li><li><strong>Comment</strong>：評論某段內容，不要求修改</li><li><strong>Global Comment</strong>：全域評論，不關聯具體文字</li></ul><p><strong>決策類型</strong>：</p><ul><li><strong>Approve</strong>：計畫沒問題，直接批准（Claude Code 會忽略註解）</li><li><strong>Request Changes</strong>：有需要修改的地方，註解傳送給 AI</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../plan-review-annotations/">新增計畫註解</a></strong>。</p><p>你會學到：</p><ul><li>如何精確使用 Delete、Replace、Comment 註解</li><li>如何新增圖像標註</li><li>如何編輯和刪除註解</li><li>註解的最佳實踐和常見情境</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開檢視原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>計畫審查 UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>註解類型定義</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/types.ts#L1-L70" target="_blank" rel="noreferrer"><code>packages/ui/types.ts</code></a></td><td>1-70</td></tr><tr><td>計畫審查伺服器</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L91-L310" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>91-310</td></tr><tr><td>API: 取得計畫內容</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L132-L134" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>132-134</td></tr><tr><td>API: 批准計畫</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L201-L277" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>201-277</td></tr><tr><td>API: 拒絕計畫</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L280-L309" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>280-309</td></tr><tr><td>Viewer 元件</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Viewer.tsx#L1-L100" target="_blank" rel="noreferrer"><code>packages/ui/components/Viewer.tsx</code></a></td><td>1-100</td></tr><tr><td>AnnotationPanel 元件</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationPanel.tsx#L1-L50" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationPanel.tsx</code></a></td><td>1-50</td></tr></tbody></table><p><strong>關鍵類型</strong>：</p><ul><li><code>AnnotationType</code>：註解類型列舉（DELETION、INSERTION、REPLACEMENT、COMMENT、GLOBAL_COMMENT）（<code>packages/ui/types.ts:1-7</code>）</li><li><code>Annotation</code>：註解介面（<code>packages/ui/types.ts:11-33</code>）</li><li><code>Block</code>：計畫區塊介面（<code>packages/ui/types.ts:35-44</code>）</li></ul><p><strong>關鍵函式</strong>：</p><ul><li><code>startPlannotatorServer()</code>：啟動計畫審查伺服器（<code>packages/server/index.ts:91</code>）</li><li><code>parseMarkdownToBlocks()</code>：將 Markdown 解析為 Blocks（<code>packages/ui/utils/parser.ts</code>）</li></ul><p><strong>API 路由</strong>：</p><ul><li><code>GET /api/plan</code>：取得計畫內容（<code>packages/server/index.ts:132</code>）</li><li><code>POST /api/approve</code>：批准計畫（<code>packages/server/index.ts:201</code>）</li><li><code>POST /api/deny</code>：拒絕計畫（<code>packages/server/index.ts:280</code>）</li></ul><p><strong>業務規則</strong>：</p><ul><li>Claude Code 批准時不傳送註解（<code>apps/hook/server/index.ts:132</code>）</li><li>OpenCode 批准時可傳送註解作為備註（<code>apps/opencode-plugin/index.ts:270</code>）</li><li>拒絕計畫時註解總是傳送（<code>apps/hook/server/index.ts:154</code>）</li></ul></details>`,112)])])}const h=n(o,[["render",l]]);export{u as __pageData,h as default};
